<template>
  <div class="container fluid mt-3">
    <div class="row">
        <div class="col-12 col-md-12">
            <ul class="nav nav-tabs" id="myTab" role="tablist">
                <li class="nav-item" role="presentation">
                    <button @click="serachOrders(9)" class="nav-link active" id="home-tab" data-bs-toggle="tab" data-bs-target="#home" type="button" role="tab" aria-controls="home" aria-selected="true">全部訂單</button>
                </li>
                <li class="nav-item" role="presentation">
                    <button @click="serachOrders(0)" class="nav-link" id="profile-tab" data-bs-toggle="tab" data-bs-target="#home" type="button" role="tab" aria-controls="home" aria-selected="false">待出貨</button>
                </li>
                <li class="nav-item" role="presentation">
                    <button @click="serachOrders(1)" class="nav-link" id="contact-tab" data-bs-toggle="tab" data-bs-target="#home" type="button" role="tab" aria-controls="home" aria-selected="false">已出貨</button>
                </li>
                </ul>
                <div class="tab-content" id="myTabContent">
                <div class="tab-pane fade show active table-responsive " id="home" role="tabpanel" aria-labelledby="home-tab">
                    <div class="table-responsive table-responsive-xxl">
                        <table class="table">
                            <thead>
                                <tr class='d-none d-md-table-row'>
                                <th scope="col" >訂單編號</th>
                                <th scope="col" >訂單成立日</th>
                                <th scope="col">付款方式</th>
                                <th scope="col">出貨狀態</th>
                                <th scope="col">操作</th>
                                </tr>
                            </thead>
                            <tbody>
                                <tr v-for="item in items" :key="item.orderId">
                                <td >{{item.orderId}}</td>
                                <td >{{item.orderDate}}</td>
                                <td>{{item.payMethod}}</td>
                                <td>{{item.deliveryStatus}}</td>
                                <td>
                                    <button @click="checkOrderDetail(item.orderId)" class="btn btn-secondary">
                                        查看詳細
                                    </button>
                                </td>
                                </tr>
                                
                            </tbody>
                        </table>
                    </div>   
                </div>
                </div>
        </div>
    </div>
  </div>
</template>

<script>
import {ref,onMounted,reactive,toRefs } from 'vue'
import axios from 'axios'
import {useRouter} from 'vue-router'
export default {
  name:'BackEndOrders',
  setup(){
    let router =useRouter()
    let text=ref('all')
    let orders=reactive({items:{}})
    
    
    function checkOrderDetail(orderId){
        router.push(`/historyorderdetail?orderid=${orderId}`)
    }

    function serachOrders(status){
        axios.post('/getorders',{'deliveryStatus':status},{headers:{'contentType':'application/json'}}).then(
            response =>{
                orders.items=response.data
            }
        ).catch(
            error =>{
                console.log(error.message)
            }
        )
    }

    onMounted(()=>{
        axios.post('/getorders',{'deliveryStatus':9},{headers:{'contentType':'application/json'}}).then(
            response =>{
                orders.items=response.data
            }
        ).catch(
            error =>{
                console.log(error.message)
            }
        )
    })
    
    return{
        text,
        serachOrders,
        ...toRefs(orders),
        checkOrderDetail
    }
  }
}
</script>

